Randomized Quicksort Implementation:Selecting a Random Pivot to Ensure Time Complexity
By choosing the pivot uniformly at random for each partition, we avoid consistently bad splits on already structured input and obtain an expected time complexity of (O(nlogn)) with high probability.
#include&lt;iostream&gt;#include&lt;vector&gt;using namespace std;int partition(vector&lt;int&gt;&amp; arr, int l, int r) &#123;	int pivot = arr[r];	int i = l;	for (int j = l; j &lt; r; j++) &#123;		if (arr[j] &lt;= pivot) &#123;			swap(arr[i++], arr[j]);		&#125;	&#125;	swap(arr[i], arr[r]);	return i;&#125;int randomPartition(vector&lt;int&gt;&amp; arr, int l, int r) &#123;	int pivotPos = (random() % (r - l + 1) + l);	swap(arr[pivotPos], arr[r]);	return partition(arr, l, r);&#125;void quichRank(vector&lt;int&gt;&amp; arr, int l, int r) &#123;	if (l &lt;= r) &#123;		int pivotPos = randomPartition(arr, l, r);		quichRank(arr, l, pivotPos - 1);		quichRank(arr, pivotPos + 1, r);	&#125;&#125;int main() &#123;	vector&lt;int&gt; arr;	for (int i = 0; i &lt; 10; i++) &#123;		arr.push_back(random()%100);	&#125;	quichRank(arr, 0, arr.size() - 1);	for (auto num : arr) &#123;		cout &lt;&lt; num &lt;&lt; &quot; &quot;;	&#125;	return 0;&#125;
